$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Vnesite število dni, koliko naj se hranijo surove statistike obiskovalcev PrestaShop. Primer: 60 pomeni, da modul obdrži zadnjih 60 dni in izbriše starejše zapise iz ps_connections, ps_connections_source in ps_connections_page. Ne nastavite na 1, razen če ste prepričani, da ne potrebujete nedavnih statistik obiskovalcev.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Velikost paketa';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Največje število povezav, obdelanih v enem paketu.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Vnesite, koliko glavnih zapisov povezav se lahko obdela v enem notranjem paketu. Manjše vrednosti so varnejše na šibkem gostovanju, vendar zahtevajo več zagonov cron. Večje vrednosti čistijo hitreje, vendar lahko dlje zadržujejo zaklepe baze podatkov. Priporočena začetna vrednost: 1000 do 5000; povečajte šele po testiranju časa izvajanja.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Največ paketov na zagon';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Omeji, koliko dela lahko opravi ena izvedba cron.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Vnesite, koliko paketov se lahko izvede med enim zagonom cron. Skupno možno število izbrisanih glavnih zapisov povezav na zagon je približno Velikost paketa krat Največ paketov na zagon. Primer: 5000 in 10 pomeni do približno 50000 glavnih zapisov v enem zagonu cron. Zmanjšajte, če se trgovina med čiščenjem upočasni.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Počisti ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Počisti predpomnilnik bloka faceted/layered iskanja z uporabo TRUNCATE TABLE. MySQL/MariaDB tabelo ponovno ustvari prazno.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Omogočite samo, če ps_layered_filter_block preveč zraste ali vsebuje zastarel predpomnilnik faceted iskanja. To ne izbriše izdelkov, kategorij ali layered indeksa cen. Po čiščenju lahko PrestaShop ali modul faceted search po potrebi ponovno zgradi predpomnilnik.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agregiraj statistiko virov prometa pred brisanjem';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Shrani dnevno povzeto statistiko virov prometa pred brisanjem surovih vrstic.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Ko je omogočeno, modul shrani majhen dnevni povzetek pred odstranitvijo surovih statistik PrestaShop. Hrani števila obiskov, ogledov strani, izvorno domeno in UTM vrednosti. Ne shranjuje IP naslovov, celotnih referrer URL-jev ali nizov user-agent. Onemogočite, če želite samo brisanje in ne potrebujete zgodovinskih povzetkov virov.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Dnevi hrambe agregiranih statistik';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Kako dolgo naj se hrani majhna dnevna povzetkovna tabela.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Vnesite, koliko dni naj agregirani povzetki prometa ostanejo v tabeli modula. Primer: 730 hrani približno dve leti dnevnih povzetkov virov. Ta nastavitev vpliva samo na tabelo ps_jooim_dbcleaner_traffic_daily, ne na izvirne statistične tabele PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Časovna omejitev zastarelega zaklepa v sekundah';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Zaščita pred istočasnim izvajanjem dveh procesov čiščenja.';
