$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_924684322fe68e56ef9205e7f480f598'] = 'Počisti predpomnilnik bloka faceted/layered iskanja z uporabo TRUNCATE TABLE. MySQL/MariaDB tabelo ponovno ustvari prazno.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Omogočite samo, če ps_layered_filter_block preveč zraste ali vsebuje zastarel predpomnilnik faceted iskanja. To ne izbriše izdelkov, kategorij ali layered indeksa cen. Po čiščenju lahko PrestaShop ali modul faceted search po potrebi ponovno zgradi predpomnilnik.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agregiraj statistiko virov prometa pred brisanjem';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Shrani dnevno povzeto statistiko virov prometa pred brisanjem surovih vrstic.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Ko je omogočeno, modul shrani majhen dnevni povzetek pred odstranitvijo surovih statistik PrestaShop. Hrani števila obiskov, ogledov strani, izvorno domeno in UTM vrednosti. Ne shranjuje IP naslovov, celotnih referrer URL-jev ali nizov user-agent. Onemogočite, če želite samo brisanje in ne potrebujete zgodovinskih povzetkov virov.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Dnevi hrambe agregiranih statistik';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Kako dolgo naj se hrani majhna dnevna povzetkovna tabela.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Vnesite, koliko dni naj agregirani povzetki prometa ostanejo v tabeli modula. Primer: 730 hrani približno dve leti dnevnih povzetkov virov. Ta nastavitev vpliva samo na tabelo ps_jooim_dbcleaner_traffic_daily, ne na izvirne statistične tabele PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Časovna omejitev zastarelega zaklepa v sekundah';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Zaščita pred istočasnim izvajanjem dveh procesov čiščenja.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Vnesite število sekund, po katerem se nedokončan zaklep čiščenja šteje za zapuščenega. To ščiti bazo pred dvema hkratnima zagonoma cron. Priporočena vrednost: 7200. Znižajte samo, če je zagotovljeno, da se cron hitro konča.';
